// Utility: shuffle array
export function shuffle(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

// Utility: randomize option order while tracking correct answer
export function randomizeOptions(q) {
  const opts = shuffle(q.options);
  return { ...q, options: opts };
}

// Pick N random questions from a pool and randomize their options
export function getRandomQuestions(pool, n = 8) {
  return shuffle(pool).slice(0, n).map(randomizeOptions);
}

